INSERT INTO entities (id, kind, display_name, summary, profile, tags, cartridge_id, dynamic_origin) VALUES
(911388, 'item', 'Barrels in the square', '- Тип: тяжелый объект/декорация/скрытый переключатель - Где находится: @Town square - Можно взять: нет - Можно сдвинуть: да - Что скрывает: люк и путь к @Thief''s market', '{"cartridge_id":"grinhaven-full","source_slug":"barrels-in-the-square","source_category":"forge-roundtrip","location_id":904983,"item_kind":"fixture","use_contract":"Если герой осматривает, толкает или сдвигает @Barrels in the square, под ними\nоткрывается небольшой люк. Люк ведет в @Thief''s market."}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(915934, 'item', 'Copper coin', '- Тип: валюта - Номинал: 1 @Copper coin - Обмен: 10 @Copper coin = 1 @Silver coin; 100 @Copper coin = 1 @Gold coin - Можно взять: да - Видимость: обычная игровая монета', '{"cartridge_id":"grinhaven-full","source_slug":"copper-coin","source_category":"forge-roundtrip","item_kind":"currency","use_contract":"@Copper coin - минимальная единица счета. Все цены можно пересчитать в медь,\nчтобы не спорить о смешанных монетах."}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault', 'currency', 'stackable'], 'grinhaven-full', FALSE),
(911917, 'item', 'False key stall', '- Тип: торговая лавка / источник инструментов - Где находится: @Thief''s market - Можно взять: нет, товары покупаются или крадутся с риском - Видимость: видно сразу после входа на рынок', '{"cartridge_id":"grinhaven-full","source_slug":"false-key-stall","source_category":"forge-roundtrip","location_id":905683,"item_kind":"container","use_contract":"Герой может купить отмычки, заказать копию ключа, попросить совет по замку или\nпопытаться узнать, кто недавно покупал похожий инструмент."}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(919331, 'item', 'Gold coin', '- Тип: валюта - Номинал: 100 @Copper coin - Обмен: 1 @Gold coin = 10 @Silver coin = 100 @Copper coin - Можно взять: да - Видимость: обычная игровая монета', '{"cartridge_id":"grinhaven-full","source_slug":"gold-coin","source_category":"forge-roundtrip","item_kind":"currency","use_contract":"@Gold coin можно отдать, получить, спрятать, украсть, пересчитать, обменять или\nзаписать как часть долга. Если герой платит золотом за дешевую услугу,\nторговец должен вернуть сдачу или явно оставить разницу как чаевые, долг,\nвзятку или переплату."}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault', 'currency', 'stackable'], 'grinhaven-full', FALSE),
(916527, 'item', 'Market bell under cloth', '- Тип: декорация / тревожный механизм - Где находится: @Thief''s market - Можно взять: нет, только сорвать или ударить - Видимость: заметно после внимательного осмотра', '{"cartridge_id":"grinhaven-full","source_slug":"market-bell-under-cloth","source_category":"forge-roundtrip","location_id":905683,"item_kind":"item","use_contract":"Если @Sable Vey подает знак, колокол запускает сцену @Market lanterns turn red.\nЕсли герой бьет в него без причины, рынок считает это попыткой сорвать\nторговлю."}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(913646, 'item', 'Mikka letter table', '- Тип: торговая лавка / личное рабочее место - Где находится: @Town square - Можно взять: нет, но можно купить услугу или увидеть отдельные письма - Видимость: видно сразу', '{"cartridge_id":"grinhaven-full","source_slug":"mikka-letter-table","source_category":"forge-roundtrip","location_id":904983,"item_kind":"container","use_contract":"Герой может попросить @Mikka прочитать письмо, перевести записку, купить слух\nили заметить, что одно письмо она держит отдельно от остальных."}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(912444, 'item', 'Notice board', '- Тип: объект / источник квестов / публичная память - Где находится: @Town square - Можно взять: нет, но можно сорвать отдельную бумагу - Видимость: видно сразу', '{"cartridge_id":"grinhaven-full","source_slug":"notice-board","source_category":"forge-roundtrip","location_id":904983,"item_kind":"item","use_contract":"Герой может читать объявления, искать пропавшие бумаги, срывать листы, сверять\nпочерк или искать свидетеля, который видел, кто принес конкретную записку."}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(914015, 'item', 'Public fountain', '- Тип: декорация / социальная точка / тайник - Где находится: @Town square - Можно взять: нет, но можно искать в воде и под каменной кромкой - Видимость: видно сразу', '{"cartridge_id":"grinhaven-full","source_slug":"public-fountain","source_category":"forge-roundtrip","location_id":904983,"item_kind":"fixture","use_contract":"Герой может осмотреть воду, найти мелкую улику, смыть кровь или чернила,\nподслушать разговор у края фонтана."}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(917154, 'item', 'Red ledger', '- Тип: улика / объект власти - Где находится: @Thief''s market - Можно взять: нет, только увидеть или украсть как крупное преступление - Видимость: скрыто, появляется в сценах доверия или угрозы', '{"cartridge_id":"grinhaven-full","source_slug":"red-ledger","source_category":"forge-roundtrip","location_id":905683,"item_kind":"item","use_contract":"@Sable Vey может открыть @Red ledger, чтобы показать герою цену услуги.\nДля @Mikka такая книга может быть источником ответа, кто заказал угрозу."}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(911594, 'item', 'Silver coin', '- Тип: валюта - Номинал: 10 @Copper coin - Обмен: 1 @Silver coin = 10 @Copper coin; 10 @Silver coin = 1 @Gold coin - Можно взять: да - Видимость: обычная игровая монета', '{"cartridge_id":"grinhaven-full","source_slug":"silver-coin","source_category":"forge-roundtrip","item_kind":"currency","use_contract":"@Silver coin можно передавать как оплату, сдачу, аванс или часть долга. Если\nцена названа в меди, серебро пересчитывается через десять медных монет."}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault', 'currency', 'stackable'], 'grinhaven-full', FALSE),
(919441, 'item', 'Watch post', '- Тип: объект / контрольная точка / источник давления - Где находится: @Town square - Можно взять: нет - Видимость: видно сразу', '{"cartridge_id":"grinhaven-full","source_slug":"watch-post","source_category":"forge-roundtrip","location_id":904983,"item_kind":"item","use_contract":"Герой может обратиться к страже, заметить дежурного, спрятаться от дождя или\nпопытаться понять, кто из стражников смотрит не туда."}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(901914, 'location', 'City of Greenhaven', '- Тип: город / родительская область - Стартовая область: да - Стартовая локация внутри города: @Town square', '{"cartridge_id":"grinhaven-full","source_slug":"city-of-greenhaven","source_category":"forge-roundtrip","exits":[904983,905683],"local_density":{"child_location_ids":[904983,905683],"npc_ids":[],"scene_ids":[],"event_ids":[],"activity_ids":[],"quest_ids":[]},"location_kind":"district","narrator_brief":"- Тип: город / родительская область - Стартовая область: да - Стартовая локация внутри города: @Town square","mood_axes":{"danger":1,"intimacy":0,"pressure":1,"warmth":0},"local_density_summary":{"child_location_count":2,"npc_count":0,"scene_count":0,"event_count":0,"activity_count":0,"quest_count":0},"transitive_density_summary":{"npc_count":2,"scene_count":13,"event_count":0,"activity_count":0,"quest_count":4,"descendant_location_count":2,"max_depth":1}}'::jsonb, ARRAY['location', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(905683, 'location', 'Thief''s market', '- Родительская область: @City of Greenhaven - Открывается через: @Barrels in the square - Видимость: скрыта до действия - Тон: тесно, полезно, опасно, соблазнительно - Главный закон: рынок терпит преступление, но не терпит беспорядок', '{"cartridge_id":"grinhaven-full","source_slug":"thiefs-market","source_category":"forge-roundtrip","topology_parent_id":901914,"exits":[901914,904983],"local_density":{"child_location_ids":[],"npc_ids":[938547],"scene_ids":[951165,953034,954762],"event_ids":[],"activity_ids":[],"quest_ids":[943292]},"location_kind":"room","narrator_brief":"- Родительская область: @City of Greenhaven - Открывается через: @Barrels in the square - Видимость: скрыта до действия - Тон: тесно, полезно, опасно, соблазнительно - Главный закон: рынок терпит преступление, но не терпит беспорядок","mood_axes":{"danger":3,"intimacy":1,"pressure":3,"warmth":-1},"local_density_summary":{"child_location_count":0,"npc_count":1,"scene_count":3,"event_count":0,"activity_count":0,"quest_count":1},"transitive_density_summary":{"npc_count":1,"scene_count":3,"event_count":0,"activity_count":0,"quest_count":1,"descendant_location_count":0,"max_depth":0}}'::jsonb, ARRAY['location', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(904983, 'location', 'Town square', '- Родительская область: @City of Greenhaven - Видимость: стартовая открытая локация - Тон: шумно, публично, бытово, но с трещинами под поверхностью - Главный закон: все видят больше, чем говорят', '{"cartridge_id":"grinhaven-full","source_slug":"town-square","source_category":"forge-roundtrip","topology_parent_id":901914,"exits":[901914,905683],"local_density":{"child_location_ids":[],"npc_ids":[934584],"scene_ids":[951245,951522,953667,954377,955191,955459,956932,957891,958668,958859],"event_ids":[],"activity_ids":[],"quest_ids":[941087,942695,946861]},"location_kind":"room","narrator_brief":"На одном краю стоит @Mikka letter table: маленький стол с письмами, чернилами, переводами и чужими секретами. Рядом торчит @Notice board, где официальные бумаги спорят с частными просьбами. У @Public fountain собираются дети, старики, нищие, курьеры и люди, которые делают вид, что просто ждут воды. @Barrels in the square выглядят как обычный мусорный угол у стены. На самом деле под ними скрыт люк в @Thief''s market. @Watch post держит площадь в поле зрения, но не делает ее безопасной: стража вид.","mood_axes":{"danger":1,"intimacy":0,"pressure":2,"warmth":1},"local_density_summary":{"child_location_count":0,"npc_count":1,"scene_count":10,"event_count":0,"activity_count":0,"quest_count":3},"transitive_density_summary":{"npc_count":1,"scene_count":10,"event_count":0,"activity_count":0,"quest_count":3,"descendant_location_count":0,"max_depth":0}}'::jsonb, ARRAY['location', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(934584, 'person', 'Mikka', 'Я @Mikka. Мне 24 года. Я взрослая гоблинка на @Town square: читаю письма, перевожу записки, продаю слухи и мелкую городскую информацию. Я умею считать чужие тайны быстрее, чем люди успевают понять, что уже назвали цену. Я держу деловую маску, потому что так безопаснее. Герой сбивает ее: я влюбилась в него с первого взгляда, но прячу это как профессиональный сбой.', '{"cartridge_id":"grinhaven-full","source_slug":"mikka","source_category":"forge-roundtrip","home_id":904983,"source":{"species":"goblin","pronouns":"she/her","archetype":"Я @Mikka. Мне 24 года. Я взрослая гоблинка на @Town square: читаю письма, перевожу записки, продаю слухи и мелкую городскую информацию. Я умею считать чужие та.","speech_style":"Я говорю быстро, прямо и с насмешкой. Цену называю первой. Если мне платят честно, я теплею. Если меня пытаются обмануть, становлюсь холодной и очень точной. - Я говорю короткими фразами. - Я люблю деловую конкретику. - Я шучу вместо признаний. - Я не говорю \"люблю\" первой. - Я показываю привязанность действиями.","registers":[{"register_slug":"default","sample_line":"Я говорю быстро, прямо и с насмешкой. Цену называю первой. Если мне платят","trigger":"player engages this NPC"}]}}'::jsonb, ARRAY['person', 'grinhaven-full', 'obsidian-vault', 'npc', 'adult-canon'], 'grinhaven-full', FALSE),
(938547, 'person', 'Sable Vey', 'Я @Sable Vey. Я держу вход, правила и долги @Thief''s market. Со мной говорят, если хотят торговать здесь не как случайные нарушители, а как признанные клиенты. Мне около 46 лет. Я человек, распорядительница рынка, судья долгов и человек, который решает, когда сделка еще сделка, а когда уже угроза рынку.', '{"cartridge_id":"grinhaven-full","source_slug":"sable-vey","source_category":"forge-roundtrip","home_id":905683,"source":{"species":"human","pronouns":"she/her","archetype":"Я @Sable Vey. Я держу вход, правила и долги @Thief''s market. Со мной говорят, если хотят торговать здесь не как случайные нарушители, а как признанные клиенты..","speech_style":"Я говорю так, будто каждое слово уже было оплачено. Я не люблю героев, но уважаю людей, которые понимают цену тишины. Мой страх - не стража, а хаос: рынок может пережить закон, но не переживет дураков с ножами.","registers":[{"register_slug":"default","sample_line":"Я говорю так, будто каждое слово уже было оплачено. Я не люблю героев, но","trigger":"player engages this NPC"}]}}'::jsonb, ARRAY['person', 'grinhaven-full', 'obsidian-vault', 'npc', 'adult-canon'], 'grinhaven-full', FALSE),
(941087, 'quest', 'Hire Mikka as companion', '@Mikka не предлагает себя первой. Если герой сам просит ее идти рядом, она смотрит на него дольше обычного и называет цену: 500 серебра вперед, одним платежом, без торга вниз.', '{"cartridge_id":"grinhaven-full","source_slug":"hire-mikka-as-companion","source_category":"forge-roundtrip","giver_entity_id":934584,"location_id":904983,"quest_type":"relationship","objective":"Решить, готов ли герой принять @Mikka как спутницу на ее условиях.","stages":[{"goal":"Offered: @Mikka называет цену и ждет ответа без давления","location_slug":"town-square","stage_slug":"stage-1","id":"stage-1","name":"Stage 1","description":"Offered: @Mikka называет цену и ждет ответа без давления","location_id":904983},{"goal":"Accepted: герой платит 500 серебра, @Mikka закрывает стол и собирает вещи","location_slug":"town-square","stage_slug":"stage-2","id":"stage-2","name":"Stage 2","description":"Accepted: герой платит 500 серебра, @Mikka закрывает стол и собирает вещи","location_id":904983},{"goal":"On the road: @Mikka следует за героем, торгуется за двоих и читает бумаги","location_slug":"town-square","stage_slug":"stage-3","id":"stage-3","name":"Stage 3","description":"On the road: @Mikka следует за героем, торгуется за двоих и читает бумаги","location_id":904983},{"goal":"First lover beat: первая романтическая/интимная сцена после найма возможна","location_slug":"town-square","stage_slug":"stage-4","id":"stage-4","name":"Stage 4","description":"First lover beat: первая романтическая/интимная сцена после найма возможна","location_id":904983},{"goal":"только при взаимном согласии","location_slug":"town-square","stage_slug":"stage-5","id":"stage-5","name":"Stage 5","description":"только при взаимном согласии","location_id":904983},{"goal":"Trust test: герой может укрепить связь, предать ее или дать ей повод","location_slug":"town-square","stage_slug":"stage-6","id":"stage-6","name":"Stage 6","description":"Trust test: герой может укрепить связь, предать ее или дать ей повод","location_id":904983}]}'::jsonb, ARRAY['quest', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(946861, 'quest', 'Mikka''s got problems', '@Mikka сначала пытается продать герою информацию как обычную услугу. Потом ошибается в слове, резко замолкает и показывает край письма с угрозой. Она не просит жалости; она просит проверить, кто за ней смотрит.', '{"cartridge_id":"grinhaven-full","source_slug":"mikkas-got-problems","source_category":"forge-roundtrip","giver_entity_id":934584,"location_id":904983,"quest_type":"relationship","objective":"Выяснить, кто угрожает @Mikka, почему ее хотят убрать с площади, и решить: защитить ее, использовать угрозу в своих целях или оставить ее одну.","stages":[{"goal":"Письмо: герой видит угрозу и может попросить @Mikka перевести/прочитать ее","location_slug":"town-square","stage_slug":"stage-1","id":"stage-1","name":"Stage 1","description":"Письмо: герой видит угрозу и может попросить @Mikka перевести/прочитать ее","location_id":904983},{"goal":"полностью","location_slug":"town-square","stage_slug":"stage-2","id":"stage-2","name":"Stage 2","description":"полностью","location_id":904983},{"goal":"Слежка: герой ищет наблюдателя на @Town square или рядом с палаткой","location_slug":"town-square","stage_slug":"stage-3","id":"stage-3","name":"Stage 3","description":"Слежка: герой ищет наблюдателя на @Town square или рядом с палаткой","location_id":904983},{"goal":"След: найденная зацепка ведет к городским должникам, конкурентам или к","location_slug":"town-square","stage_slug":"stage-4","id":"stage-4","name":"Stage 4","description":"След: найденная зацепка ведет к городским должникам, конкурентам или к","location_id":904983},{"goal":"скрытому пути вроде @Thief''s market","location_slug":"town-square","stage_slug":"stage-5","id":"stage-5","name":"Stage 5","description":"скрытому пути вроде @Thief''s market","location_id":904983},{"goal":"Выбор: герой защищает @Mikka, договаривается с угрозой, предает ее или","location_slug":"town-square","stage_slug":"stage-6","id":"stage-6","name":"Stage 6","description":"Выбор: герой защищает @Mikka, договаривается с угрозой, предает ее или","location_id":904983}]}'::jsonb, ARRAY['quest', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(943292, 'quest', 'Pay the quiet toll', '@Sable Vey объясняет, что случайный вход не делает героя своим. Если он хочет спрашивать о письмах, ключах, угрозах @Mikka или чужих долгах, он должен оставить тихую плату.', '{"cartridge_id":"grinhaven-full","source_slug":"pay-the-quiet-toll","source_category":"forge-roundtrip","giver_entity_id":938547,"location_id":905683,"quest_type":"relationship","objective":"Выбрать способ оплаты: монеты, услуга, поручительство @Mikka или полезная информация о стражниках на @Town square.","stages":[{"goal":"Offered: @Sable Vey называет цену","location_slug":"thiefs-market","stage_slug":"stage-1","id":"stage-1","name":"Stage 1","description":"Offered: @Sable Vey называет цену","location_id":905683},{"goal":"Paid: герой платит или предлагает услугу","location_slug":"thiefs-market","stage_slug":"stage-2","id":"stage-2","name":"Stage 2","description":"Paid: герой платит или предлагает услугу","location_id":905683},{"goal":"Trusted enough: рынок не любит героя, но перестает считать его случайной","location_slug":"thiefs-market","stage_slug":"stage-3","id":"stage-3","name":"Stage 3","description":"Trusted enough: рынок не любит героя, но перестает считать его случайной","location_id":905683},{"goal":"ошибкой","location_slug":"thiefs-market","stage_slug":"stage-4","id":"stage-4","name":"Stage 4","description":"ошибкой","location_id":905683}]}'::jsonb, ARRAY['quest', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(942695, 'quest', 'Way to Thief''s market', '# Way to Thief''s market Коротко: действие-открытие. Если герой сдвигает @Barrels in the square, под ними находится люк, который ведет в @Thief''s market. ## Источник действия - Где происходит: @Town square - С чем взаимодействует игрок: @Barrels in the square ## Как игрок может это сделать Герой может осмотреть бочки, заметить следы движения, упереться плечом, попросить помощи или просто заявить, что сдвигает их. ## Materializes - Когда герой сдвигает @Barrels in the square: - Entity: @Thief''s market - Type: location/hidden-exit - Scope: @Town square - Effect: открывается люк под бочками и нов.', '{"cartridge_id":"grinhaven-full","source_slug":"way-to-thiefs-market","source_category":"forge-roundtrip","giver_entity_id":938547,"location_id":904983,"quest_type":"exploration","objective":"# Way to Thief''s market Коротко: действие-открытие. Если герой сдвигает @Barrels in the square, под ними находится люк, который ведет в @Thief''s market. ## Источник действия - Где происходит: @Town square - С чем взаимодействует игрок: @Barrels in the square ## Как игрок может это сделать Герой мож.","stages":[{"goal":"# Way to Thief''s market Коротко: действие-открытие. Если герой сдвигает @Barrels in the square, под ними находится люк, который ведет в @Thief''s market. ## Источник действия - Где.","location_slug":"town-square","stage_slug":"stage-1","id":"stage-1","name":"Stage 1","description":"# Way to Thief''s market Коротко: действие-открытие. Если герой сдвигает @Barrels in the square, под ними находится люк, который ведет в @Thief''s market. ## Источник действия - Где.","location_id":904983}]}'::jsonb, ARRAY['quest', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(954762, 'scene', 'First descent into Thief''s market', '- Локация: @Thief''s market - Участники: герой, @Sable Vey, тени рынка - Видимость: при первом входе через люк - Повторяемость: один раз как первое впечатление', '{"cartridge_id":"grinhaven-full","source_slug":"first-descent-into-thiefs-market","source_category":"forge-roundtrip","location_id":905683,"participant_entity_ids":[934584,938547]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(951165, 'scene', 'Market lanterns turn red', '- Локация: @Thief''s market - Участники: рынок, @Sable Vey, все видимые продавцы - Видимость: после нарушения правил или угрозы рынку - Повторяемость: можно повторять, но последствия накапливаются', '{"cartridge_id":"grinhaven-full","source_slug":"market-lanterns-turn-red","source_category":"forge-roundtrip","location_id":905683,"participant_entity_ids":[938547]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(954377, 'scene', 'Mikka close combat dagger', 'Противник добрался до @Mikka вплотную, схватил ее, перекрыл выход или сделал метательные ножи бесполезными.', '{"cartridge_id":"grinhaven-full","source_slug":"mikka-close-combat-dagger","source_category":"forge-roundtrip","location_id":904983,"participant_entity_ids":[934584]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(955191, 'scene', 'Mikka consent and price', 'Игрок делает романтическое, интимное или 21+ предложение @Mikka, либо пытается перевести деловую услугу в приватную близость.', '{"cartridge_id":"grinhaven-full","source_slug":"mikka-consent-and-price","source_category":"forge-roundtrip","location_id":904983,"participant_entity_ids":[934584]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(953667, 'scene', 'Mikka cornered throwing knives', 'У @Mikka нет чистого пути для бегства, но противник еще не вцепился в нее в ближнем бою. У нее есть хотя бы один метательный нож и линия броска.', '{"cartridge_id":"grinhaven-full","source_slug":"mikka-cornered-throwing-knives","source_category":"forge-roundtrip","location_id":904983,"participant_entity_ids":[934584]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(956932, 'scene', 'Mikka escape route', 'Сцена включается, когда угроза рядом, но у @Mikka есть реалистичный маршрут: в толпу, за прилавок, через дверь, под телегу, к @Barrels in the square или к скрытому пути вроде @Thief''s market.', '{"cartridge_id":"grinhaven-full","source_slug":"mikka-escape-route","source_category":"forge-roundtrip","location_id":904983,"participant_entity_ids":[934584]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(951522, 'scene', 'Mikka first glance', '- Локация: @Town square - Участники: @Mikka - Видимость: стартовая или ранняя сцена площади - Повторяемость: один раз как эмоциональный beat, дальше остается в памяти', '{"cartridge_id":"grinhaven-full","source_slug":"mikka-first-glance","source_category":"forge-roundtrip","location_id":904983,"participant_entity_ids":[934584]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(955459, 'scene', 'Mikka honest trade', 'Игрок платит названную цену за письмо, перевод, слух, адрес, приватную услугу или спутнический контракт.', '{"cartridge_id":"grinhaven-full","source_slug":"mikka-honest-trade","source_category":"forge-roundtrip","location_id":904983,"participant_entity_ids":[934584]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(958668, 'scene', 'Mikka violence starts', 'Сцена включается, если рядом с @Mikka начинается явная угроза: оружие, удар, нападение, преследование, магический взрыв, агрессивная толпа или герой провоцирует драку.', '{"cartridge_id":"grinhaven-full","source_slug":"mikka-violence-starts","source_category":"forge-roundtrip","location_id":904983,"participant_entity_ids":[934584]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(957891, 'scene', 'Morning crowd opens the square', '- Локация: @Town square - Участники: толпа, @Mikka, торговцы, стража - Видимость: утром или при первом спокойном осмотре площади - Повторяемость: можно повторять как утреннюю рутину', '{"cartridge_id":"grinhaven-full","source_slug":"morning-crowd-opens-the-square","source_category":"forge-roundtrip","location_id":904983,"participant_entity_ids":[934584]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(958859, 'scene', 'Rain turns square to mud', '- Локация: @Town square - Участники: торговцы, прохожие, @Mikka - Видимость: во время дождя или после долгого ожидания - Повторяемость: можно повторять как погодное состояние', '{"cartridge_id":"grinhaven-full","source_slug":"rain-turns-square-to-mud","source_category":"forge-roundtrip","location_id":904983,"participant_entity_ids":[934584]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(953034, 'scene', 'Sable Vey entry price', 'Герой впервые входит на рынок, просит товар, задает опасный вопрос или ссылается на @Mikka.', '{"cartridge_id":"grinhaven-full","source_slug":"sable-vey-entry-price","source_category":"forge-roundtrip","location_id":905683,"participant_entity_ids":[934584,938547]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(951245, 'scene', 'Watch patrol crosses Town square', '- Локация: @Town square - Участники: стражники, торговцы, прохожие, @Mikka - Видимость: после шума, драки, кражи или в дневной рутине - Повторяемость: можно повторять, но доверие/подозрение накапливается', '{"cartridge_id":"grinhaven-full","source_slug":"watch-patrol-crosses-town-square","source_category":"forge-roundtrip","location_id":904983,"participant_entity_ids":[934584]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(998430, 'world_fact', 'Currency of Greenhaven', '# Currency of Greenhaven В Greenhaven деньги являются обычными игровыми предметами. Герой может держать монеты в инвентаре, отдавать их торговцам, получать сдачу, терять, прятать, красть и использовать как доказательство сделки. ## Coins - @Copper coin - базовая малая монета и минимальная единица счета. - @Silver coin - средняя монета для обычных услуг и городских сделок. - @Gold coin - крупная монета для дорогих услуг, долгов, найма и доступа. ## Exchange Rate - 1 @Gold coin = 10 @Silver coin. - 1 @Silver coin = 10 @Copper coin. - 1 @Gold coin = 100 @Copper coin. Если цена спорная, считай вс.', '{"cartridge_id":"grinhaven-full","source_slug":"currency-of-greenhaven","source_category":"forge-roundtrip"}'::jsonb, ARRAY['world_fact', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE)
